values.content:
=Sos un asistente de triage de leads comerciales. Clasificá el siguiente lead como VIP, Normal o Descartar, y justificá brevemente tu decisión.

Nombre: {{ $json.fields.Nombre }}
Empresa: {{ $json.fields.Empresa }}
Email: {{ $json.fields.Email }}
Mensaje: {{ $json.fields.Mensaje }}

Respondé ÚNICAMENTE con un JSON válido, sin texto adicional, con este formato exacto:
{"clasificacion": "VIP|Normal|Descartar", "justificacion": "..."}

parameters.jsCode:
const item = $input.first().json;
// La salida de Gemini puede venir ya simplificada como texto, como objeto JSON directo, o dentro de content/candidates según versión del nodo.
let raw = item.content?.parts?.[0]?.text || item.text || item.response || item;
let parsed;
try {
  if (typeof raw === 'object') {
    parsed = raw;
  } else {
    const clean = String(raw).replace(/```json|```/g, '').trim();
    parsed = JSON.parse(clean);
  }
} catch (e) {
  parsed = { clasificacion: 'Normal', justificacion: 'No se pudo parsear la respuesta de la IA: ' + JSON.stringify(raw) };
}
return [{ json: parsed }];

